import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Webcam from "react-webcam";
import axios from 'axios';

const StudyRoom = ({ task }) => {
    const { id } = useParams();
    const navigate = useNavigate();
    
    const [seconds, setSeconds] = useState(25 * 60);
    const [isActive, setIsActive] = useState(false);
    const [showExplanation, setShowExplanation] = useState(false);
    const [explanation, setExplanation] = useState("");
    const webcamRef = useRef(null);

    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => setSeconds((prev) => prev - 1), 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            setShowExplanation(true); // Trigger explanation when timer ends
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    const handleFinish = async (isCompleted) => {
        try {
            const status = isCompleted ? 'completed' : 'missed';
            await axios.patch(`/api/tasks/${id}`, { 
                status, 
                userExplanation: explanation 
            }, {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });
            navigate('/planPage');
        } catch (error) {
            console.error("Update failed", error);
        }
    };

    return (
        <div className="study-room-container" style={{ display: 'flex', gap: '20px', padding: '20px' }}>
            {/* Left Side: Video & Camera */}
            <div style={{ flex: 1 }}>
                <div className="video-box">
                    <iframe width="100%" height="300" src={`https://www.youtube.com/embed?listType=search&list=${task?.title}+tutorial`} title="Tutorial" allowFullScreen></iframe>
                </div>
                <div className="camera-box" style={{ marginTop: '20px' }}>
                    <p>Monitoring Active...</p>
                    <Webcam audio={false} ref={webcamRef} screenshotFormat="image/jpeg" width="100%" />
                </div>
            </div>

            {/* Right Side: Timer & Controls */}
            <div style={{ flex: 1, textAlign: 'center' }}>
                <h2>{task?.title}</h2>
                <div style={{ fontSize: '3rem', margin: '20px' }}>
                    {Math.floor(seconds / 60)}:{String(seconds % 60).padStart(2, '0')}
                </div>
                
                {!showExplanation ? (
                    <button onClick={() => setIsActive(!isActive)}>
                        {isActive ? 'Pause Study' : 'Start Day 1'}
                    </button>
                ) : (
                    <div className="explanation-area">
                        <h3>Study Session Ended</h3>
                        <textarea 
                            placeholder="Briefly explain what you learned..." 
                            value={explanation}
                            onChange={(e) => setExplanation(e.target.value)}
                            style={{ width: '100%', height: '100px' }}
                        />
                        <div style={{ marginTop: '10px' }}>
                            <button onClick={() => handleFinish(true)} style={{ backgroundColor: 'green', color: 'white' }}>
                                Submit & Mark Completed
                            </button>
                            <button onClick={() => handleFinish(false)} style={{ marginLeft: '10px' }}>
                                Not Ready (Reschedule)
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default StudyRoom;
